class ImagesController < ApplicationController
  require 'tempfile'

  def convert
    uploaded_file = params[:file]
    format = params[:format]
    size = params[:size]

    if uploaded_file.present? && format.present? && size.present?
      temp_file = Tempfile.new(['source', File.extname(uploaded_file.original_filename)])
      temp_file.binmode
      temp_file.write(uploaded_file.read)
      temp_file.rewind

      output_file = Tempfile.new(['output', ".#{format}"])
      output_file.binmode

      system("convert #{temp_file.path} -resize #{size} #{output_file.path}")

      send_file output_file.path, type: "image/#{format}", disposition: 'inline'
    else
      render json: { error: 'Missing parameters' }, status: :unprocessable_entity
    end
  end
end